def data_transformer(data: dict) -> dict:
    """Transform structured data: filter, map, reshape."""
    records = data.get("records", [])
    operations = data.get("operations", [])

    result = list(records)
    for op in operations:
        op_type = op.get("type")
        if op_type == "filter":
            field = op["field"]
            value = op["value"]
            result = [r for r in result if r.get(field) == value]
        elif op_type == "rename":
            old_name = op["from"]
            new_name = op["to"]
            result = [{new_name if k == old_name else k: v for k, v in r.items()} for r in result]
        elif op_type == "select":
            fields = op["fields"]
            result = [{k: r.get(k) for k in fields} for r in result]

    return {"transformed": result, "count": len(result)}
